import{c as s,Q as e,j as i,m as t}from"./chunks/framework.Bhbi9jCp.js";const k=JSON.parse('{"title":"移动端打包与签名管理","description":"","frontmatter":{},"headers":[],"relativePath":"mobileCommonLearning/04-移动端打包与签名管理.md","filePath":"mobileCommonLearning/04-移动端打包与签名管理.md","lastUpdated":1780912084000}'),n={name:"mobileCommonLearning/04-移动端打包与签名管理.md"};function p(l,a,d,r,o,h){return e(),i("div",null,[...a[0]||(a[0]=[t(`<h1 id="移动端打包与签名管理" tabindex="-1">移动端打包与签名管理 <a class="header-anchor" href="#移动端打包与签名管理" aria-label="Permalink to &quot;移动端打包与签名管理&quot;">​</a></h1><p>签名不是发布流程里的一个勾选项。签名决定这个包是不是你发的,也决定用户能不能覆盖升级。</p><p>一句话先记住:<strong>移动端签名 = 用私钥证明这个安装包属于某个开发者或团队。</strong></p><hr><h2 id="一、android-打包机制" tabindex="-1">一、Android 打包机制 <a class="header-anchor" href="#一、android-打包机制" aria-label="Permalink to &quot;一、Android 打包机制&quot;">​</a></h2><p>Android 常见产物:</p><table tabindex="0"><thead><tr><th>产物</th><th>用途</th></tr></thead><tbody><tr><td>APK</td><td>可直接安装</td></tr><tr><td>AAB</td><td>上传 Google Play,由商店按设备生成 APK</td></tr></tbody></table><p>典型流程:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Java / Kotlin / Dart</span></span>
<span class="line"><span>  -&gt; .class</span></span>
<span class="line"><span>  -&gt; D8 / R8 -&gt; classes.dex</span></span>
<span class="line"><span>  -&gt; aapt2 编译资源</span></span>
<span class="line"><span>  -&gt; 合并 AndroidManifest.xml</span></span>
<span class="line"><span>  -&gt; 打包 APK / AAB</span></span>
<span class="line"><span>  -&gt; release keystore 签名</span></span>
<span class="line"><span>  -&gt; zipalign / optimize</span></span></code></pre></div><p>关键点:</p><ul><li>同一个已发布应用,后续更新必须保持 <code>applicationId</code> 和签名兼容。</li><li>如果不使用 Google Play App Signing 托管,release keystore 丢失通常意味着旧用户无法无缝升级。</li><li>国内多渠道分发时,release keystore 是最高优先级资产。</li></ul><hr><h2 id="二、ios-打包机制" tabindex="-1">二、iOS 打包机制 <a class="header-anchor" href="#二、ios-打包机制" aria-label="Permalink to &quot;二、iOS 打包机制&quot;">​</a></h2><p>iOS 常见产物:</p><table tabindex="0"><thead><tr><th>产物</th><th>用途</th></tr></thead><tbody><tr><td><code>.app</code></td><td>应用 bundle</td></tr><tr><td><code>.ipa</code></td><td>可分发安装包</td></tr><tr><td><code>.xcarchive</code></td><td>Xcode Archive 产物,用于导出 IPA 或上传</td></tr></tbody></table><p>典型流程:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Swift / Objective-C / Dart</span></span>
<span class="line"><span>  -&gt; native binary</span></span>
<span class="line"><span>  -&gt; .app bundle</span></span>
<span class="line"><span>  -&gt; 写入 Info.plist / Frameworks / Assets</span></span>
<span class="line"><span>  -&gt; 配置 entitlements</span></span>
<span class="line"><span>  -&gt; certificate + private key 签名</span></span>
<span class="line"><span>  -&gt; archive</span></span>
<span class="line"><span>  -&gt; upload App Store Connect</span></span></code></pre></div><p>关键点:</p><ul><li>App Store 更新主要依赖同一 Apple Developer Team 下的 Bundle ID。</li><li>不强制使用旧 Mac 的同一个私钥。</li><li>有账号完整权限时,可以重新生成证书和 profile 继续更新 App Store 版本。</li></ul><hr><h2 id="三、android-签名材料" tabindex="-1">三、Android 签名材料 <a class="header-anchor" href="#三、android-签名材料" aria-label="Permalink to &quot;三、Android 签名材料&quot;">​</a></h2><p>你需要保管:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>release.jks / release.keystore</span></span>
<span class="line"><span>keyAlias</span></span>
<span class="line"><span>storePassword</span></span>
<span class="line"><span>keyPassword</span></span>
<span class="line"><span>key.properties</span></span>
<span class="line"><span>签名证书指纹:MD5 / SHA1 / SHA256</span></span></code></pre></div><p>典型 <code>key.properties</code>:</p><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">storeFile</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=../release.jks</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">storePassword</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=***</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">keyAlias</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=release</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">keyPassword</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=***</span></span></code></pre></div><p>不要提交:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>*.jks</span></span>
<span class="line"><span>*.keystore</span></span>
<span class="line"><span>key.properties</span></span></code></pre></div><hr><h2 id="四、ios-签名材料" tabindex="-1">四、iOS 签名材料 <a class="header-anchor" href="#四、ios-签名材料" aria-label="Permalink to &quot;四、iOS 签名材料&quot;">​</a></h2><p>iOS 签名材料:</p><table tabindex="0"><thead><tr><th>项目</th><th>Apple 是否保存</th><th>说明</th></tr></thead><tbody><tr><td>Apple Developer 账号</td><td>是</td><td>开发者身份</td></tr><tr><td>Team ID</td><td>是</td><td>团队标识</td></tr><tr><td>Bundle ID / App ID</td><td>是</td><td>App 身份</td></tr><tr><td>Certificate <code>.cer</code></td><td>部分</td><td>Apple 签发证书</td></tr><tr><td>Private Key</td><td>否</td><td>本地钥匙串生成,Apple 不保存</td></tr><tr><td>Provisioning Profile</td><td>是</td><td>绑定 App、证书、设备、能力</td></tr><tr><td>Entitlements</td><td>部分</td><td>项目声明 + profile 约束</td></tr><tr><td><code>.p12</code></td><td>否</td><td>证书 + 私钥导出</td></tr></tbody></table><p>关键结论:</p><ul><li><code>.cer</code> 不等于完整签名身份。</li><li>真正能签名的是&quot;证书 + 私钥&quot;。</li><li><code>.p12</code> 通常包含证书和私钥。</li><li>只有 <code>.cer</code> 和 <code>.mobileprovision</code>,没有私钥,本机不能用旧 identity 签名。</li></ul><hr><h2 id="五、换设备怎么处理" tabindex="-1">五、换设备怎么处理 <a class="header-anchor" href="#五、换设备怎么处理" aria-label="Permalink to &quot;五、换设备怎么处理&quot;">​</a></h2><h3 id="android" tabindex="-1">Android <a class="header-anchor" href="#android" aria-label="Permalink to &quot;Android&quot;">​</a></h3><p>强烈建议迁移旧签名材料。</p><p>必须备份:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>.jks / .keystore</span></span>
<span class="line"><span>key.properties</span></span>
<span class="line"><span>keyAlias</span></span>
<span class="line"><span>storePassword</span></span>
<span class="line"><span>keyPassword</span></span></code></pre></div><p>没有这些,很多渠道无法覆盖更新。</p><h3 id="ios" tabindex="-1">iOS <a class="header-anchor" href="#ios" aria-label="Permalink to &quot;iOS&quot;">​</a></h3><p>App Store 场景通常可以重新生成:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Xcode 登录 Apple ID</span></span>
<span class="line"><span>选择正确 Team</span></span>
<span class="line"><span>Automatically manage signing</span></span>
<span class="line"><span>重新生成 / 下载 certificate 和 profile</span></span>
<span class="line"><span>Archive 上传</span></span></code></pre></div><p>建议迁移旧 <code>.p12</code> 的场景:</p><ul><li>CI/CD 依赖固定证书</li><li>手动签名</li><li>企业包 / Ad Hoc</li><li>证书数量达到上限</li><li>三方系统记录了证书或推送相关材料</li></ul><hr><h2 id="六、签名指纹怎么查" tabindex="-1">六、签名指纹怎么查 <a class="header-anchor" href="#六、签名指纹怎么查" aria-label="Permalink to &quot;六、签名指纹怎么查&quot;">​</a></h2><p>查看 APK 签名:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">apksigner</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> verify</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --print-certs</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app-release.apk</span></span></code></pre></div><p>查看 keystore:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">keytool</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -list</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -keystore</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> release.keystore</span></span></code></pre></div><p>这些指纹要记录:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>MD5</span></span>
<span class="line"><span>SHA1</span></span>
<span class="line"><span>SHA256</span></span></code></pre></div><p>很多开放平台需要 SHA1 / SHA256。</p><hr><h2 id="七、flutter-场景" tabindex="-1">七、Flutter 场景 <a class="header-anchor" href="#七、flutter-场景" aria-label="Permalink to &quot;七、Flutter 场景&quot;">​</a></h2><p>Flutter 本质仍然走各平台签名:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">flutter</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apk</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --release</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">flutter</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> appbundle</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --release</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">flutter</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ios</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --release</span></span></code></pre></div><p>Flutter 只负责构建跨端代码,不替你解决:</p><ul><li>Android release keystore</li><li>iOS certificate / profile</li><li>App Store Connect</li><li>Play Console</li><li>国内渠道签名变更</li></ul><p>Flutter 项目也必须按原生平台管理签名资产。</p><hr><h2 id="八、什么时候会出事故" tabindex="-1">八、什么时候会出事故 <a class="header-anchor" href="#八、什么时候会出事故" aria-label="Permalink to &quot;八、什么时候会出事故&quot;">​</a></h2><ol><li>把 debug keystore 当 release 用。</li><li>keystore 放在离职同事电脑里,没有备份。</li><li>只有 iOS <code>.cer</code>,没有私钥,CI 不能签。</li><li>profile 没包含 Push / Associated Domains,Archive 能过但线上能力失效。</li><li>重新生成 Android keystore 后发包,老用户不能覆盖安装。</li><li>签名指纹没同步到微信 / 地图 / 推送平台。</li></ol><hr><h2 id="九、检查清单" tabindex="-1">九、检查清单 <a class="header-anchor" href="#九、检查清单" aria-label="Permalink to &quot;九、检查清单&quot;">​</a></h2><ul><li>[ ] Android release keystore 是否加密备份</li><li>[ ] keystore 密码是否在密码管理器</li><li>[ ] key.properties 是否不进 git</li><li>[ ] iOS <code>.p12</code> 是否能在新机器导入</li><li>[ ] profile 是否匹配 Bundle ID 和能力</li><li>[ ] 签名指纹是否记录</li><li>[ ] CI/CD 是否通过 Secret 注入签名材料</li><li>[ ] release 包是否用正式签名真机测试</li></ul><hr><h2 id="十、心智模型" tabindex="-1">十、心智模型 <a class="header-anchor" href="#十、心智模型" aria-label="Permalink to &quot;十、心智模型&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Android:keystore 是覆盖升级生命线</span></span>
<span class="line"><span>iOS:Team + Bundle ID + certificate/private key/profile 是签名链</span></span>
<span class="line"><span>Flutter:仍然要回到 Android / iOS 签名体系</span></span>
<span class="line"><span>CI:签名材料必须可恢复、可审计、不可泄漏</span></span></code></pre></div><p>下一篇 05 讲 Android keystore、AAB、APK 与签名轮换。</p>`,71)])])}const g=s(n,[["render",p]]);export{k as __pageData,g as default};
